package com.example.orders;

import java.math.BigDecimal;
import java.util.Optional;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.verifyNoInteractions;
import static org.mockito.Mockito.verifyNoMoreInteractions;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
class OrderServiceTest {

    @Mock
    private ProductRepository productRepository;

    @Mock
    private OrderRepository orderRepository;

    @Mock
    private PaymentGateway paymentGateway;

    @Mock
    private NotificationService notificationService;

    @InjectMocks
    private OrderService orderService;

    @Test
    void placeOrder_whenRequestIsNull_shouldThrowIllegalArgumentException() {
        IllegalArgumentException exception =
                assertThrows(IllegalArgumentException.class, () -> orderService.placeOrder(null));

        assertEquals("Request cannot be null", exception.getMessage());
        verifyNoInteractions(productRepository, orderRepository, paymentGateway, notificationService);
    }

    @Test
    void placeOrder_whenCustomerIdIsBlankOrWhitespace_shouldThrowIllegalArgumentExceptionAndNotCallDependencies() {
        String[] invalidCustomerIds = {"", "   "};

        for (String customerId : invalidCustomerIds) {
            OrderRequest request = new OrderRequest(customerId, "p-100", 1);
            IllegalArgumentException exception =
                    assertThrows(IllegalArgumentException.class, () -> orderService.placeOrder(request));

            assertEquals("Customer id cannot be blank", exception.getMessage());
            verifyNoInteractions(productRepository, orderRepository, paymentGateway, notificationService);
        }
    }


    @Test
    void testProductId(){

        String[] invalidProductId = {"", "   ", null};

        for(String invalidProduct: invalidProductId){
            OrderRequest orderRequest = new OrderRequest("12", invalidProduct, 12);

            IllegalArgumentException exception = 
            assertThrows(IllegalArgumentException.class, () -> orderService.placeOrder(orderRequest));

            assertEquals("Product id cannot be blank", exception.getMessage());
            verifyNoInteractions(notificationService, orderRepository, productRepository, paymentGateway);
        }
    }


    @Test
    void placeOrder_whenProductNotFound_shouldThrowProductNotFoundException() {
        OrderRequest request = new OrderRequest("cust-1", "missing-product", 1);
        when(productRepository.findById("missing-product")).thenReturn(Optional.empty());

        ProductNotFoundException exception =
                assertThrows(ProductNotFoundException.class, () -> orderService.placeOrder(request));

        assertEquals("Product not found: missing-product", exception.getMessage());
        verify(productRepository).findById("missing-product");
        verifyNoInteractions(orderRepository, paymentGateway, notificationService);
    }


    @Test
    void placeOrder_whenProductIsInactive_shouldThrowInactiveProductException() {
        Product inactiveProduct = new Product("p-200", "Old Monitor", new BigDecimal("250"), 10, false);
        OrderRequest request = new OrderRequest("cust-2", "p-200", 1);
        when(productRepository.findById("p-200")).thenReturn(Optional.of(inactiveProduct));

        InactiveProductException exception =
                assertThrows(InactiveProductException.class, () -> orderService.placeOrder(request));

        assertEquals("Product is inactive: p-200", exception.getMessage());
        verify(productRepository).findById("p-200");
        verifyNoInteractions(paymentGateway, orderRepository, notificationService);
        verifyNoMoreInteractions(productRepository);
    }

}
